query:
{
  gkeClusters(
    where: {
      OR: [
        { currentMasterVersion_STARTS_WITH: "1.30" }
        { currentNodeVersion_STARTS_WITH: "1.30" }
        { nodePools_SOME: { version_STARTS_WITH: "1.30" } }
      ]
    }
  ) {
    ...AssetFragment
    currentMasterVersion
    currentNodeVersion
    releaseChannel
    nodePools {
      name
      version
      managementAutoUpgrade
    }
  }
}
